enum SeatType {
    Regular,
    Premium,
    VIP
};

type Ticket = [string, number, SeatType, number];

let ticket1 : Ticket  = [
    "sanam teri kasam",
    143,
    SeatType.VIP,
    899

];



function calculateDiscount(ticket : Ticket): number {
    if(ticket[2] === SeatType.VIP)
    {
        let res = ticket[3]-(ticket[3]*0.20);
        return res;
    }
    else if(ticket[2] === SeatType.Premium)
    {
        let res =  ticket[3]-(ticket[3]*0.10);
        return res;
    }
    else{
        return ticket[3];
    }

}

console.log(calculateDiscount(ticket1));
console.log(ticket1);